patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index e1923a344179..595b0a7399d6 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -3505,6 +3505,23 @@ Instruction *InstCombinerImpl::visitOr(BinaryOperator &I) {
     Value *IncrementY = Builder.CreateAdd(Y, ConstantInt::get(Ty, 1));
     return BinaryOperator::CreateMul(X, IncrementY);
   }
+  // Fold (div * C) + rem -> div * (C - Divisor) + val when the or is disjoint.
+  Value *Div, *Val;
+  const APInt *Divisor, *Shift;
+  if (match(&I, m_c_DisjointOr(m_OneUse(m_Shl(m_Value(Div), m_APInt(Shift))),
+                               m_URem(m_Value(Val), m_APInt(Divisor)))) &&
+      match(Div, m_UDiv(m_Specific(Val), m_APInt(Divisor)))) {
+    // Shift must be less than bit width.
+    if (Shift->uge(Ty->getScalarSizeInBits()))
+      return nullptr;
+    APInt PowerOfTwo = APInt::getOneBitSet(Ty->getScalarSizeInBits(), Shift->getZExtValue());
+    if (PowerOfTwo.uge(*Divisor)) {
+      APInt NewMulC = PowerOfTwo - *Divisor;
+      Value *NewMul = Builder.CreateMul(Div, ConstantInt::get(Ty, NewMulC));
+      Value *Add = Builder.CreateAdd(Val, NewMul);
+      return replaceInstUsesWith(I, Add);
+    }
+  }

   // (A & C) | (B & D)
   Value *A, *B, *C, *D;

